// ESP32 Dual-Core RTOS Hub
// Board-specific features not available on classic AVR Arduino:
// - xTaskCreatePinnedToCore (core affinity)
// - FreeRTOS Queue handoff between tasks
// - ADC on GPIO34 (input-only ESP32 pin)

#if !defined(ARDUINO_ARCH_ESP32)
#error This sketch targets ESP32 only (wokwi-esp32-devkit-v1).
#endif

#include <Arduino.h>

const int BUTTON_PIN = 15;
const int LED_PIN = 2;
const int ADC_PIN = 34;

QueueHandle_t sensorQueue;

struct SensorMsg {
  uint16_t adc;
  bool pressed;
  uint32_t ms;
};

void sensorTask(void* /*arg*/) {
  pinMode(BUTTON_PIN, INPUT_PULLUP);
  for (;;) {
    SensorMsg msg;
    msg.adc = analogRead(ADC_PIN);
    msg.pressed = (digitalRead(BUTTON_PIN) == LOW);
    msg.ms = millis();
    xQueueOverwrite(sensorQueue, &msg);
    vTaskDelay(pdMS_TO_TICKS(40));
  }
}

void controlTask(void* /*arg*/) {
  pinMode(LED_PIN, OUTPUT);
  SensorMsg msg{};
  for (;;) {
    if (xQueueReceive(sensorQueue, &msg, pdMS_TO_TICKS(100)) == pdTRUE) {
      int threshold = map(msg.adc, 0, 4095, 100, 3500);
      bool on = msg.pressed || (msg.adc > threshold);
      digitalWrite(LED_PIN, on ? HIGH : LOW);

      Serial.print("[core ");
      Serial.print(xPortGetCoreID());
      Serial.print("] t=");
      Serial.print(msg.ms);
      Serial.print(" adc=");
      Serial.print(msg.adc);
      Serial.print(" threshold=");
      Serial.print(threshold);
      Serial.print(" btn=");
      Serial.print(msg.pressed ? 1 : 0);
      Serial.print(" led=");
      Serial.println(on ? 1 : 0);
    }
  }
}

void setup() {
  Serial.begin(115200);
  delay(200);
  Serial.println("ESP32 Dual-Core RTOS Hub");

  analogReadResolution(12);
  sensorQueue = xQueueCreate(1, sizeof(SensorMsg));

  xTaskCreatePinnedToCore(sensorTask, "sensorTask", 4096, nullptr, 1, nullptr, 0);
  xTaskCreatePinnedToCore(controlTask, "controlTask", 4096, nullptr, 1, nullptr, 1);
}

void loop() {
  // Main loop intentionally idle: work is handled by two RTOS tasks.
  vTaskDelay(pdMS_TO_TICKS(1000));
}
